import { useState, useEffect, useCallback, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Check, Crown, Loader2, Zap, Globe, TrendingUp, Users, ExternalLink } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { useTranslation } from "react-i18next";
import { useCreateMembershipOrder } from "@/hooks/useMembershipOrders";

const PRODUCT_ID = "VIP1";

const Membership = () => {
  const { toast } = useToast();
  const { user } = useAuth();
  const { t } = useTranslation();
  const [purchasing, setPurchasing] = useState(false);
  const createOrder = useCreateMembershipOrder();
  const pendingOrderIdRef = useRef<string | null>(null);

  const handlePurchaseResult = useCallback(async (msg: string, transactionId?: string) => {
    setPurchasing(false);
    const msgStr = String(msg);

    // Map msg to status
    let status = "failed";
    if (msgStr === "success") status = "success";
    else if (msgStr === "userCancelled") status = "cancelled";
    else if (msgStr === "pending") status = "pending";

    // Record order to database
    try {
      await createOrder.mutateAsync({
        product_id: PRODUCT_ID,
        status,
        apple_transaction_id: transactionId || undefined,
        amount: 9.99,
        currency: "USD",
        platform: "ios",
        error_message: status === "failed" ? msgStr : undefined,
      });
    } catch (e) {
      console.error("Failed to save order:", e);
    }

    if (msgStr === "success") {
      toast({ title: t("membership.toast.success"), description: t("membership.toast.successDesc") });
    } else if (msgStr === "userCancelled") {
      toast({ title: t("membership.toast.cancelled"), description: t("membership.toast.cancelledDesc") });
    } else if (msgStr === "pending") {
      toast({ title: t("membership.toast.pending"), description: t("membership.toast.pendingDesc") });
    } else {
      toast({ title: t("membership.toast.failed"), description: `${t("membership.toast.error")}: ${msgStr}`, variant: "destructive" });
    }
  }, [toast, t, createOrder]);

  useEffect(() => {
    (window as any).onReceivePurchase = (msg: any, transactionId?: any) => {
      console.log("Received purchase result:", msg, "transactionId:", transactionId);
      handlePurchaseResult(String(msg), transactionId ? String(transactionId) : undefined);
    };
    return () => { delete (window as any).onReceivePurchase; };
  }, [handlePurchaseResult]);

  const handlePurchase = () => {
    if (!user) {
      toast({ title: t("membership.toast.loginRequired"), description: t("membership.toast.loginRequiredDesc"), variant: "destructive" });
      return;
    }
    setPurchasing(true);
    try {
      const webkit = (window as any).webkit;
      if (webkit?.messageHandlers?.VoiceBridge) {
        webkit.messageHandlers.VoiceBridge.postMessage(`purchase:${PRODUCT_ID}`);
      } else {
        setPurchasing(false);
        toast({ title: t("membership.toast.notice"), description: t("membership.toast.purchaseInApp"), variant: "destructive" });
      }
    } catch {
      setPurchasing(false);
      toast({ title: t("membership.toast.error"), description: t("membership.toast.connectionError"), variant: "destructive" });
    }
  };

  const trafficFeatures = [
    { icon: Globe, titleKey: "membership.feature.website", descKey: "membership.feature.websiteDesc" },
    { icon: ExternalLink, titleKey: "membership.feature.delivery", descKey: "membership.feature.deliveryDesc" },
    { icon: Users, titleKey: "membership.feature.booking", descKey: "membership.feature.bookingDesc" },
    { icon: TrendingUp, titleKey: "membership.feature.exposure", descKey: "membership.feature.exposureDesc" },
  ];

  const checklistKeys = [
    "membership.checklist.unlockLinks",
    "membership.checklist.trafficPool",
    "membership.checklist.linkManagement",
    "membership.checklist.badge",
  ];

  return (
    <div className="min-h-screen bg-background pb-24">
      <div className="px-5 pt-10 pb-6 max-w-lg mx-auto space-y-8">
        {/* Hero */}
        <div className="text-center space-y-4">
          <div className="inline-flex items-center justify-center h-16 w-16 rounded-2xl bg-gradient-to-br from-primary/20 to-primary/5 border border-primary/20">
            <Crown className="h-8 w-8 text-primary" />
          </div>
          <h1 className="text-2xl font-bold">{t("membership.title")}</h1>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.subtitle")}
          </p>
        </div>

        {/* What is Traffic Pool */}
        <div className="rounded-xl border bg-card p-5 space-y-4">
          <div className="flex items-center gap-2">
            <Zap className="h-5 w-5 text-primary" />
            <h2 className="font-semibold text-base">{t("membership.whatIsTrafficPool")}</h2>
          </div>
          <p className="text-sm text-muted-foreground leading-relaxed">
            {t("membership.trafficPoolDesc")}
          </p>
        </div>

        {/* Features */}
        <div className="space-y-3">
          <h2 className="font-semibold text-base px-1">{t("membership.benefits")}</h2>
          <div className="grid gap-3">
            {trafficFeatures.map((f, i) => (
              <div key={i} className="flex items-start gap-3 rounded-xl border bg-card p-4">
                <div className="flex-shrink-0 h-9 w-9 rounded-lg bg-primary/10 flex items-center justify-center">
                  <f.icon className="h-4.5 w-4.5 text-primary" />
                </div>
                <div className="space-y-0.5">
                  <p className="text-sm font-medium">{t(f.titleKey)}</p>
                  <p className="text-xs text-muted-foreground">{t(f.descKey)}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Price */}
        <div className="rounded-xl border-2 border-primary/30 bg-primary/5 p-5 text-center space-y-2">
          <p className="text-sm text-muted-foreground">{t("membership.monthlySubscription")}</p>
          <div>
            <span className="text-4xl font-extrabold">$9.99</span>
            <span className="text-sm text-muted-foreground ml-1">/{t("membership.perMonth")}</span>
          </div>
          <p className="text-xs text-muted-foreground">{t("membership.autoRenew")}</p>
        </div>

        {/* Checklist */}
        <div className="space-y-2 px-1">
          {checklistKeys.map((key, i) => (
            <div key={i} className="flex items-center gap-2.5">
              <Check className="h-4 w-4 text-primary flex-shrink-0" />
              <span className="text-sm">{t(key)}</span>
            </div>
          ))}
        </div>

        {/* CTA */}
        <Button
          className="w-full h-12 text-base font-semibold"
          onClick={handlePurchase}
          disabled={purchasing}
        >
          {purchasing ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              {t("membership.processing")}
            </>
          ) : (
            t("membership.subscribe")
          )}
        </Button>

        {/* Footer */}
        <div className="text-center space-y-1 text-[11px] text-muted-foreground">
          <p>{t("membership.autoRenewNote")}</p>
          <p>
            {t("membership.agreeToTerms")}{" "}
            <a href="/terms-of-service" className="underline text-primary">{t("membership.termsOfService")}</a>
            {" & "}
            <a href="/privacy-policy" className="underline text-primary">{t("membership.privacyPolicy")}</a>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Membership;
